39	architecture rtl of psi_fix_sqrt is
40	
41	  -- Constants
42	  constant InFmtNorm_c          : psi_fix_fmt_t := (0, 0, in_fmt_g.I + in_fmt_g.F);
43	  constant OutFmtNorm_c         : psi_fix_fmt_t := (out_fmt_g.S, 0, out_fmt_g.I + out_fmt_g.F + 1); -- rounding bit is kept
44	  constant SqrtInFmt_c          : psi_fix_fmt_t := (0, 0, 20);
45	  constant SqrtOutFmt_c         : psi_fix_fmt_t := (0, 0, 17);
46	  constant MaxSft_c             : natural     := (InFmtNorm_c.F / 2 * 2);
47	  constant SftStgBeforeApprox_c : natural     := log2(MaxSft_c);
48	  constant SftStgAfterApprox_c  : natural     := SftStgBeforeApprox_c / 2;
49	  constant OutSftFmt_c          : psi_fix_fmt_t := (out_fmt_g.S, 0, OutFmtNorm_c.F);
50	  constant NormSft_c            : integer     := (in_fmt_g.I + 1) / 2 * 2;
51	
52	  -- types
53	  type CntArray_t is array (natural range <>) of unsigned(SftStgBeforeApprox_c - 1 downto 0);
54	  type OutSftArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(OutSftFmt_c) - 1 downto 0);
55	  type InSftArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
56	
57	  -- Two Process Method
58	  type two_process_r is record
59	    InVld  : std_logic_vector(0 to 1 + SftStgBeforeApprox_c - 1);
60	    Norm_0 : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
61	    InSft  : InSftArray_t(0 to SftStgBeforeApprox_c - 1);
62	    SftCnt : CntArray_t(0 to SftStgBeforeApprox_c - 1);
63	    OutVld : std_logic_vector(0 to SftStgAfterApprox_c + 1);
64	    OutSft : OutSftArray_t(0 to SftStgAfterApprox_c);
65	    OutCnt : CntArray_t(0 to SftStgAfterApprox_c);
66	    OutRes : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
67	  end record;
68	  signal r, r_next : two_process_r;
69	
70	  -- Component Instantiation
71	  signal SqrtIn_s    : std_logic_vector(psi_fix_size(SqrtInFmt_c) - 1 downto 0);
72	  signal SftCntOut_s : std_logic_vector(SftStgBeforeApprox_c - 1 downto 0);
73	  signal IsZeroIn_s  : std_logic;
74	  signal IsZeroOut_s : std_logic;
75	  signal SqrtVld_s   : std_logic;
76	  signal SqrtData_s  : std_logic_vector(psi_fix_size(SqrtOutFmt_c) - 1 downto 0);
77	
78	begin
79	  --------------------------------------------------------------------------
80	  -- Assertions
81	  --------------------------------------------------------------------------
82	  assert in_fmt_g.S = 0 report "###ERROR###: psi_fix_sqrt in_fmt_g must be unsigned!" severity error;
83	
84	  --------------------------------------------------------------------------
85	  -- Combinatorial Process
86	  --------------------------------------------------------------------------
87	  proc_comb : process(r, vld_i, dat_i, SftCntOut_s, SqrtVld_s, SqrtData_s, IsZeroOut_s)
88	    variable v              : two_process_r;
89	    variable SftBeforeIn_v  : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
90	    variable SftBefore_v    : integer;
91	    variable SftAfter_v     : unsigned(SftStgBeforeApprox_c downto 0);
92	    variable SftStepAfter_v : integer;
93	    variable StgIdx_v       : integer;
94	  begin
95	    -- hold variables stable
96	    v := r;
97	
98	    -- *** Pipe Handling ***
99	    v.InVld(v.InVld'low + 1 to v.InVld'high)    := r.InVld(r.InVld'low to r.InVld'high - 1);
100	    v.OutVld(v.OutVld'low + 1 to v.OutVld'high) := r.OutVld(r.OutVld'low to r.OutVld'high - 1);
101	
102	    -- *** Stage 0 ***
103	    -- Input Registers
104	    v.InVld(0) := vld_i;
105	    v.Norm_0   := psi_fix_shift_right(dat_i, in_fmt_g, NormSft_c, NormSft_c, InFmtNorm_c, psi_fix_trunc, psi_fix_wrap);
106	
107	    -- *** Shift stages (0 ... x) ***
108	    for stg in 0 to SftStgBeforeApprox_c - 1 loop
109	      -- Select input
110	      if stg = 0 then
111	        SftBeforeIn_v := r.Norm_0;
112	        v.SftCnt(stg) := (others => '0');
113	      else
114	        SftBeforeIn_v := r.InSft(stg - 1);
115	        v.SftCnt(stg) := r.SftCnt(stg - 1);
116	      end if;
117	
118	      -- Do Shift
119	      SftBefore_v := 2**(SftStgBeforeApprox_c - stg);
120	      if unsigned(SftBeforeIn_v(SftBeforeIn_v'left downto SftBeforeIn_v'left - SftBefore_v + 1)) = 0 then
121	        v.InSft(stg)                                  := SftBeforeIn_v(SftBeforeIn_v'left - SftBefore_v downto 0) & zeros_vector(SftBefore_v);
122	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '1';
123	      else
124	        v.InSft(stg)                                  := SftBeforeIn_v;
125	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '0';
126	      end if;
127	    end loop;
128	
129	    -- *** Out Stage 0 ***
130	    v.OutVld(0) := SqrtVld_s;
131	    if IsZeroOut_s = '1' then
132	      v.OutSft(0) := (others => '0');
133	    else
134	      v.OutSft(0) := psi_fix_resize(SqrtData_s, SqrtOutFmt_c, OutSftFmt_c);
135	    end if;
136	    v.OutCnt(0) := unsigned(SftCntOut_s);
137	
138	    -- *** Out Shift Stages ***
139	    for stg in 0 to SftStgAfterApprox_c - 1 loop
140	      -- Zero extend shift
141	      SftAfter_v := resize(r.OutCnt(stg), SftAfter_v'length);
142	
143	      -- Shift
144	      v.OutCnt(stg + 1) := r.OutCnt(stg);
145	      StgIdx_v          := SftStgAfterApprox_c - 1 - stg;
146	      SftStepAfter_v    := 2**(2 * (StgIdx_v));
147	      v.OutSft(stg + 1) := psi_fix_shift_right(r.OutSft(stg), OutFmtNorm_c, to_integer(r.OutCnt(stg)(2 * StgIdx_v + 1 downto 2 * StgIdx_v)) * SftStepAfter_v, 3 * SftStepAfter_v, OutFmtNorm_c, psi_fix_trunc, psi_fix_wrap, true);
148	    end loop;
149	
150	    -- *** Output resize ***
151	    v.OutRes := psi_fix_shift_left(r.OutSft(r.OutSft'high), OutFmtNorm_c, NormSft_c / 2, NormSft_c / 2, out_fmt_g, round_g, sat_g);
152	
153	    -- Apply to record
154	    r_next <= v;
155	
156	  end process;
157	
158	  --------------------------------------------------------------------------
159	  -- Output Assignment
160	  --------------------------------------------------------------------------
161	  dat_o <= r.OutRes;
162	  vld_o <= r.OutVld(r.OutVld'high);
163	
164	  --------------------------------------------------------------------------
165	  -- Sequential Process
166	  --------------------------------------------------------------------------
167	  proc_seq : process(clk_i)
168	  begin
169	    if rising_edge(clk_i) then
170	      r <= r_next;
171	      if rst_i = rst_pol_g then
172	        r.InVld  <= (others => '0');
173	        r.OutVld <= (others => '0');
174	      end if;
175	    end if;
176	  end process;
177	
178	  --------------------------------------------------------------------------
179	  -- Component Instantiation
180	  --------------------------------------------------------------------------
181	  SqrtIn_s   <= psi_fix_resize(r.InSft(r.InSft'high), InFmtNorm_c, SqrtInFmt_c);
182	  IsZeroIn_s <= '1' when unsigned(SqrtIn_s) = 0 else '0';
183	  inst_sqrt : entity work.psi_fix_lin_approx_sqrt18b
184	    port map(
185	      clk_i     => clk_i,
186	      rst_i     => rst_i,
187	      vld_i   => r.InVld(r.InVld'high),
188	      dat_i  => SqrtIn_s,
189	      vld_o  => SqrtVld_s,
190	      dat_o => SqrtData_s
191	    );
192	
193	  -- Count delayed with FIFO to stay working of delay of the approximation should hcange in future
194	  fifo : block
195	    signal FifoIn, FifoOut : std_logic_vector(SftStgBeforeApprox_c downto 0);
196	  begin
197	    FifoIn      <= IsZeroIn_s & std_logic_vector(r.SftCnt(r.SftCnt'high));
198	    inst_sft_del : entity work.psi_common_sync_fifo
199	      generic map(
200	        width_g       => SftStgBeforeApprox_c + 1,
201	        depth_g       => 16,
202	        ram_behavior_g => ram_behavior_g
203	      )
204	      port map(
205	        clk_i     => clk_i,
206	        rst_i     => rst_i,
207	        dat_i  => FifoIn,
208	        vld_i   => r.InVld(r.InVld'high),
209	        dat_o => FifoOut,
210	        rdy_i  => SqrtVld_s
211	      );
212	    SftCntOut_s <= FifoOut(SftCntOut_s'high downto 0);
213	    IsZeroOut_s <= FifoOut(FifoOut'high);
214	  end block;
215	
216	end rtl;
