34	  -- Constants
35	  constant InFmtNorm_c          : psi_fix_fmt_t := (0, 1, in_fmt_g.I + in_fmt_g.F);
36	  constant OutFmtNorm_c         : psi_fix_fmt_t := (0, 1 + in_fmt_g.F, out_fmt_g.I + out_fmt_g.F);
37	  constant InvInFmt_c           : psi_fix_fmt_t := (0, 1, 18);
38	  constant InvOutFmt_c          : psi_fix_fmt_t := (0, 0, 18);
39	  constant MaxSft_c             : natural     := InFmtNorm_c.F;
40	  constant SftStgBeforeApprox_c : natural     := log2ceil(MaxSft_c);
41	  constant SftStgAfterApprox_c  : natural     := SftStgBeforeApprox_c;
42	  constant NormSft_c            : integer     := in_fmt_g.I - 1;
43	  constant AbsFmt_c             : psi_fix_fmt_t := (0, in_fmt_g.I, in_fmt_g.F);
44	  constant AbsFullFmt_c         : psi_fix_fmt_t := (0, AbsFmt_c.I + 1, AbsFmt_c.F);
45	
46	  -- types
47	  type CntArray_t is array (natural range <>) of unsigned(SftStgBeforeApprox_c - 1 downto 0);
48	  type OutSftArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(OutFmtNorm_c) - 1 downto 0);
49	  type InSftArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
50	
51	  -- Two Process Method
52	  type two_process_r is record
53	    InVld     : std_logic_vector(0 to 3 + SftStgBeforeApprox_c - 1);
54	    InSign    : std_logic_vector(0 to 3 + SftStgBeforeApprox_c - 1);
55	    AbsFull_0 : std_logic_vector(psi_fix_size(AbsFullFmt_c) - 1 downto 0);
56	    Abs_1     : std_logic_vector(psi_fix_size(AbsFmt_c) - 1 downto 0);
57	    Norm_2    : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
58	    InSft     : InSftArray_t(0 to SftStgBeforeApprox_c - 1);
59	    SftCnt    : CntArray_t(0 to SftStgBeforeApprox_c - 1);
60	    OutVld    : std_logic_vector(0 to SftStgAfterApprox_c + 2);
61	    OutSign   : std_logic_vector(0 to SftStgAfterApprox_c + 1);
62	    OutSft    : OutSftArray_t(0 to SftStgAfterApprox_c);
63	    OutCnt    : CntArray_t(0 to SftStgAfterApprox_c);
64	    Denorm    : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
65	    OutRes    : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
66	  end record;
67	  signal r, r_next : two_process_r;
68	
69	  -- Component Instantiation
70	  signal InvIn_s     : std_logic_vector(psi_fix_size(InvInFmt_c) - 1 downto 0);
71	  signal SftCntOut_s : std_logic_vector(SftStgBeforeApprox_c - 1 downto 0);
72	  signal SignIn_s    : std_logic;
73	  signal SignOut_s   : std_logic;
74	  signal InvVld_s    : std_logic;
75	  signal InvData_s   : std_logic_vector(psi_fix_size(InvOutFmt_c) - 1 downto 0);
76	
77	begin
78	  --------------------------------------------------------------------------
79	  -- Assertions
80	  --------------------------------------------------------------------------
81	  -- None
82	
83	  --------------------------------------------------------------------------
84	  -- Combinatorial Process
85	  --------------------------------------------------------------------------
86	  proc_comb : process(r, vld_i, dat_i, SftCntOut_s, InvVld_s, InvData_s, SignOut_s)
87	    variable v              : two_process_r;
88	    variable SftBeforeIn_v  : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
89	    variable SftBefore_v    : integer;
90	    variable SftAfter_v     : unsigned(SftStgBeforeApprox_c downto 0);
91	    variable SftStepAfter_v : integer;
92	    variable StgIdx_v       : integer;
93	  begin
94	    -- hold variables stable
95	    v := r;
96	
97	    -- *** Pipe Handling ***
98	    v.InVld(v.InVld'low + 1 to v.InVld'high)       := r.InVld(r.InVld'low to r.InVld'high - 1);
99	    v.OutVld(v.OutVld'low + 1 to v.OutVld'high)    := r.OutVld(r.OutVld'low to r.OutVld'high - 1);
100	    v.InSign(v.InSign'low + 1 to v.InSign'high)    := r.InSign(r.InSign'low to r.InSign'high - 1);
101	    v.OutSign(v.OutSign'low + 1 to v.OutSign'high) := r.OutSign(r.OutSign'low to r.OutSign'high - 1);
102	
103	    -- *** Stage 0 ***
104	    -- Input Registers
105	    v.InVld(0)  := vld_i;
106	    if in_fmt_g.S = 0 then
107	      v.InSign(0) := '0';
108	    else
109	      v.InSign(0) := dat_i(dat_i'high);
110	    end if;
111	    v.AbsFull_0 := psi_fix_abs(dat_i, in_fmt_g, AbsFullFmt_c, psi_fix_trunc, psi_fix_wrap);
112	
113	    -- *** Stage 1 ***
114	    v.Abs_1 := psi_fix_resize(r.AbsFull_0, AbsFullFmt_c, AbsFmt_c, psi_fix_trunc, psi_fix_sat);
115	
116	    -- *** Stage 2 ***
117	    if NormSft_c > 0 then
118	      v.Norm_2 := psi_fix_shift_right(r.Abs_1, AbsFmt_c, NormSft_c, NormSft_c, InFmtNorm_c, psi_fix_trunc, psi_fix_wrap);
119	    else
120	      v.Norm_2 := psi_fix_shift_left(r.Abs_1, AbsFmt_c, -NormSft_c, -NormSft_c, InFmtNorm_c, psi_fix_trunc, psi_fix_wrap);
121	    end if;
122	
123	    -- *** Shift stages (0 ... x) ***
124	    for stg in 0 to SftStgBeforeApprox_c - 1 loop
125	      -- Select input
126	      if stg = 0 then
127	        SftBeforeIn_v := r.Norm_2;
128	        v.SftCnt(stg) := (others => '0');
129	      else
130	        SftBeforeIn_v := r.InSft(stg - 1);
131	        v.SftCnt(stg) := r.SftCnt(stg - 1);
132	      end if;
133	
134	      -- Do Shift
135	      SftBefore_v := 2**(SftStgBeforeApprox_c - stg - 1);
136	      if unsigned(SftBeforeIn_v(SftBeforeIn_v'left downto SftBeforeIn_v'left - SftBefore_v + 1)) = 0 then
137	        v.InSft(stg)                                  := SftBeforeIn_v(SftBeforeIn_v'left - SftBefore_v downto 0) & zeros_vector(SftBefore_v);
138	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '1';
139	      else
140	        v.InSft(stg)                                  := SftBeforeIn_v;
141	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '0';
142	      end if;
143	    end loop;
144	
145	    -- *** Out Stage 0 ***
146	    v.OutVld(0)  := InvVld_s;
147	    v.OutSign(0) := SignOut_s;
148	    v.OutSft(0)  := psi_fix_resize(InvData_s, InvOutFmt_c, OutFmtNorm_c);
149	    v.OutCnt(0)  := unsigned(SftCntOut_s);
150	
151	    -- *** Out Shift Stages ***
152	    for stg in 0 to SftStgAfterApprox_c - 1 loop
153	      -- Zero extend shift
154	      SftAfter_v := resize(r.OutCnt(stg), SftAfter_v'length);
155	
156	      -- Shift
157	      v.OutCnt(stg + 1) := r.OutCnt(stg);
158	      StgIdx_v          := SftStgAfterApprox_c - 1 - stg;
159	      SftStepAfter_v    := 2**(StgIdx_v);
160	      --v.OutSft(stg+1) := psi_fix_shift_left(r.OutSft(stg), OutFmtNorm_c, 0, SftStepAfter_v, OutFmtNorm_c, psi_fix_trunc, psi_fix_wrap, true);
161	      v.OutSft(stg + 1) := psi_fix_shift_left(r.OutSft(stg), OutFmtNorm_c, to_integer(r.OutCnt(stg)(StgIdx_v downto StgIdx_v)) * SftStepAfter_v, SftStepAfter_v, OutFmtNorm_c, psi_fix_trunc, psi_fix_wrap, true);
162	    end loop;
163	
164	    -- *** Denormalize ***
165	    if NormSft_c > 0 then
166	      v.Denorm := psi_fix_shift_right(r.OutSft(r.OutSft'high), OutFmtNorm_c, NormSft_c, NormSft_c, out_fmt_g, round_g, sat_g);
167	    else
168	      v.Denorm := psi_fix_shift_left(r.OutSft(r.OutSft'high), OutFmtNorm_c, -NormSft_c, -NormSft_c, out_fmt_g, round_g, sat_g);
169	    end if;
170	
171	    -- Sign Handling
172	    if in_fmt_g.S = 0 or r.OutSign(r.OutSign'high) = '0' then
173	      v.OutRes := r.Denorm;
174	    else
175	      v.OutRes := psi_fix_neg(r.Denorm, out_fmt_g, out_fmt_g, psi_fix_trunc, sat_g);
176	    end if;
177	
178	    -- Apply to record
179	    r_next <= v;
180	
181	  end process;
182	
183	  --------------------------------------------------------------------------
184	  -- Output Assignment
185	  --------------------------------------------------------------------------
186	  dat_o <= r.OutRes;
187	  vld_o <= r.OutVld(r.OutVld'high);
188	
189	  --------------------------------------------------------------------------
190	  -- Sequential Process
191	  --------------------------------------------------------------------------
192	  proc_seq : process(clk_i)
193	  begin
194	    if rising_edge(clk_i) then
195	      r <= r_next;
196	      if rst_i = '1' then
197	        r.InVld  <= (others => '0');
198	        r.OutVld <= (others => '0');
199	      end if;
200	    end if;
201	  end process;
202	
203	  --------------------------------------------------------------------------
204	  -- Component Instantiation
205	  --------------------------------------------------------------------------
206	  InvIn_s  <= psi_fix_resize(r.InSft(r.InSft'high), InFmtNorm_c, InvInFmt_c);
207	  SignIn_s <= r.InSign(r.InSign'high);
208	  inst_sqrt : entity work.psi_fix_lin_approx_inv18b
209	    port map(
210	      clk_i     => clk_i,
211	      rst_i     => rst_i,
212	      vld_i   => r.InVld(r.InVld'high),
213	      dat_i  => InvIn_s,
214	      vld_o  => InvVld_s,
215	      dat_o => InvData_s
216	    );
217	
218	  -- Count delayed with FIFO to stay working of delay of the approximation should hcange in future
219	  fifo : block
220	    signal FifoIn, FifoOut : std_logic_vector(SftStgBeforeApprox_c downto 0);
221	    signal SftCntLim       : std_logic_vector(SftStgBeforeApprox_c - 1 downto 0);
222	  begin
223	    SftCntLim   <= std_logic_vector(to_unsigned(MaxSft_c, SftCntLim'length)) when unsigned(r.SftCnt(r.SftCnt'high)) > MaxSft_c else std_logic_vector(r.SftCnt(r.SftCnt'high));
224	    FifoIn      <= SignIn_s & SftCntLim;
225	    inst_sft_del : entity work.psi_common_sync_fifo
226	      generic map(
227	        width_g       => SftStgBeforeApprox_c + 1,
228	        depth_g       => 16,
229	        ram_behavior_g => ram_behavior_g
230	      )
231	      port map(
232	        clk_i     => clk_i,
233	        rst_i     => rst_i,
234	        dat_i  => FifoIn,
235	        vld_i   => r.InVld(r.InVld'high),
236	        dat_o => FifoOut,
237	        rdy_i  => InvVld_s
238	      );
239	    SftCntOut_s <= FifoOut(SftCntOut_s'high downto 0);
240	    SignOut_s   <= FifoOut(FifoOut'high);
241	  end block;
242	
243	end architecture;
